if (! function_exists('text_rhyme_finder')) {
    function text_rhyme_finder($word, $wordlist, $mode = null, $max_results = null)
    {
        $word = trim($word);
        if (empty($word) || !is_array($wordlist) || empty($wordlist)) {
            return json_encode(['error' => 'Word and non-empty wordlist are required', 'matches' => []]);
        }
        $max = isset($max_results) && $max_results > 0 ? (int)$max_results : 20;
        $mode = isset($mode) ? $mode : 'rhyme';
        $word = mb_strtolower($word);
        $wordlist = array_map(function($w) { return mb_strtolower(trim($w)); }, $wordlist);
        $wordlist = array_values(array_unique(array_filter($wordlist, function($w) { return $w !== ''; })));

        // Remove the target word itself from candidates
        $candidates = array_values(array_filter($wordlist, function($w) use ($word) { return $w !== $word; }));

        $scores = [];

        foreach ($candidates as $candidate) {
            $score = 0;

            if ($mode === 'alliteration') {
                // Same first 1-3 letters
                $len = min(strlen($word), strlen($candidate), 3);
                $matchLen = 0;
                for ($i = 0; $i < $len; $i++) {
                    if ($word[$i] === $candidate[$i]) $matchLen++;
                    else break;
                }
                if ($matchLen >= 1) {
                    $score = $matchLen; // 1-3 points
                }
            } else {
                $wLen = strlen($word);
                $cLen = strlen($candidate);

                // Normal rhyme: match last 2-4 characters
                for ($suffixLen = 4; $suffixLen >= 2; $suffixLen--) {
                    if ($wLen >= $suffixLen && $cLen >= $suffixLen) {
                        $wSuffix = substr($word, -$suffixLen);
                        $cSuffix = substr($candidate, -$suffixLen);
                        if ($wSuffix === $cSuffix) {
                            $score = $suffixLen * 10; // Longer suffix match = better
                            break;
                        }
                    }
                }

                // Near rhyme: match last 3 chars (if normal rhyme failed)
                if ($score === 0 && $mode === 'near_rhyme') {
                    for ($suffixLen = 3; $suffixLen >= 2; $suffixLen--) {
                        if ($wLen >= $suffixLen && $cLen >= $suffixLen) {
                            $wSuffix = substr($word, -$suffixLen);
                            $cSuffix = substr($candidate, -$suffixLen);
                            if ($wSuffix === $cSuffix) {
                                $score = $suffixLen * 5;
                                break;
                            }
                        }
                    }
                }

                // Bonus: same vowel sound in the last stressed syllable (heuristic)
                if ($score > 0) {
                    $vowels = 'aeiouy';
                    $wLastVowel = -1;
                    for ($i = $wLen - 1; $i >= 0; $i--) {
                        if (strpos($vowels, $word[$i]) !== false) {
                            $wLastVowel = $i;
                            break;
                        }
                    }
                    $cLastVowel = -1;
                    for ($i = $cLen - 1; $i >= 0; $i--) {
                        if (strpos($vowels, $candidate[$i]) !== false) {
                            $cLastVowel = $i;
                            break;
                        }
                    }
                    // If both have vowels, check what follows
                    if ($wLastVowel >= 0 && $cLastVowel >= 0) {
                        $wAfter = substr($word, $wLastVowel);
                        $cAfter = substr($candidate, $cLastVowel);
                        $common = 0;
                        $minLen = min(strlen($wAfter), strlen($cAfter));
                        for ($i = 0; $i < $minLen; $i++) {
                            if ($wAfter[$i] === $cAfter[$i]) $common++;
                            else break;
                        }
                        $score += $common;
                    }
                }
            }

            if ($score > 0) {
                $scores[] = [
                    'word' => $candidate,
                    'score' => $score,
                    'type' => $mode,
                ];
            }
        }

        // Sort by score descending
        usort($scores, function($a, $b) { return $b['score'] - $a['score']; });

        $results = array_slice($scores, 0, $max);

        return json_encode([
            'word' => $word,
            'mode' => $mode,
            'candidates_checked' => count($candidates),
            'matches_found' => count($scores),
            'matches' => $results,
        ]);
